class Solution {
public:
    string shortestPalindrome(string s) {
        string rev = s;
        reverse(rev.begin(), rev.end());
        string res = rev + s;
        while (res.find(s) != string::npos) {
            rev = rev.substr(1) + rev[0];
            res = rev + s;
        }
        return res;
    }
};
```
